chapter.programlisting:
CREATE EXTENSION mobilitydb CASCADE;
-- NOTICE:  installing required extension "postgis"
-- NOTICE:  installing required extension "postgis_raster"

listitem.programlisting:
-- Elevation profile per trip (requires a loaded elevation raster) SELECT tripid, raster_value(elev, trip4326) AS elevation FROM trips, elevation_raster;
-- Average elevation per trip SELECT tripid, avgValue(raster_value(elev, trip4326)) AS mean_elev FROM trips, elevation_raster;
-- Trips that crossed terrain above 200 m SELECT tripid FROM trips, elevation_raster WHERE atValues(raster_value(elev, trip4326), floatspan '[200, 9999]') IS NOT NULL;
